// For each slideshow item, expand into 3 frame sub-items.
// Each frame gets a purpose-specific prompt, persona-specific visual style,
// and carries forward all parent fields plus frame_index and frame_purpose.
const FRAME_PURPOSES = [
  { index: 0, purpose: 'intro',   instruction: 'Introduce the concept visually with a clear title and bold key term.' },
  { index: 1, purpose: 'detail',  instruction: 'Show the key detail, diagram, or worked example for this concept.' },
  { index: 2, purpose: 'summary', instruction: 'Summarise the takeaway in one memorable visual with the main insight.' },
];

const PERSONA_STYLE = {
  'doodle-prof':    'hand-drawn sketch style, black pen lines on white paper, comic panel layout, no human faces',
  'meme-lord':      'bold Impact-font meme layout, high contrast, classic meme template aesthetic, no human faces',
  'exam-gremlin':   'stark warning-poster style, red accents, bold sans-serif text, no human faces',
  'lecture-bestie': 'pastel lavender and mint colour palette, friendly infographic style, rounded shapes, no human faces',
  'study-bard':     'lyric-card style, musical-note motifs, sky blue and white, elegant serif font, no human faces',
  'problem-grinder':'step-by-step diagram with numbered boxes and arrows, clean technical illustration, no human faces',
};
const DEFAULT_STYLE = 'clean educational infographic, minimal flat design, no human faces';

const items = $input.all();
const results = [];
for (const item of items) {
  const d = item.json;
  const topic    = d.title ?? d.chunk_text.slice(0, 100);
  const excerpt  = d.chunk_text.slice(0, 300);
  const style    = PERSONA_STYLE[d.persona_slug] ?? DEFAULT_STYLE;

  for (const frame of FRAME_PURPOSES) {
    results.push({
      json: {
        ...d,
        frame_index:   frame.index,
        frame_purpose: frame.purpose,
        image_prompt:  `Portrait 9:16 educational image. Topic: "${topic}". ${frame.instruction} Excerpt: ${excerpt}. Visual style: ${style}.`,
      }
    });
  }
}
return results;

const responses  = $input.all();
const prompts    = $('Build image prompts').all();

const results = [];
for (let i = 0; i < responses.length; i++) {
  const response = responses[i].json;
  const prev     = prompts[i].json;

  const prediction = response?.predictions?.[0];
  if (!prediction) continue;

  const b64      = prediction.bytesBase64Encoded;
  const mimeType = prediction.mimeType ?? 'image/png';
  const ext      = mimeType.includes('jpeg') ? 'jpg' : 'png';
  const fileName = `${prev.persona_slug}-${prev.chunk_index}-frame-${prev.frame_index}.${ext}`;
  const filePath = `${prev.material_id}/${fileName}`;

  results.push({
    json: {
      ...prev,
      mime_type: mimeType,
      file_path: filePath,
      file_name: fileName,
    },
    binary: {
      image_data: { data: b64, mimeType, fileName }
    }
  });
}
return results;

// Collect the 3 uploaded frame URLs back into one item per original slideshow post.
// Items arrive grouped: frames 0, 1, 2 for post A, then 0, 1, 2 for post B, etc.
// We identify parent items by (material_id + persona_slug + chunk_index).
const uploads   = $input.all();
const extracted = $('Extract image data').all();
const supabaseUrl = $vars.SUPABASE_URL;

// Build a key → [frameUrl] map
const groups = {};
for (let i = 0; i < uploads.length; i++) {
  const prev     = extracted[i].json;
  const frameUrl = `${supabaseUrl}/storage/v1/object/public/post-media/${prev.file_path}`;
  const key      = `${prev.material_id}|${prev.persona_slug}|${prev.chunk_index}`;
  if (!groups[key]) {
    groups[key] = { meta: prev, frames: [] };
  }
  groups[key].frames[prev.frame_index] = frameUrl;
}

return Object.values(groups).map(g => ({ json: { ...g.meta, frame_urls: g.frames } }));

// Build a short spoken voiceover script from the chunk text.
// Keep to 2-3 sentences so it fits a ~7-second clip across 3 frames.
const PERSONA_VOICE_STYLE = {
  'lecture-bestie': 'friendly and encouraging',
  'exam-gremlin':   'urgent and sharp',
  'problem-grinder':'methodical and clear',
  'doodle-prof':    'playful and curious',
  'meme-lord':      'casual and punchy',
  'study-bard':     'poetic and musical',
};

const items = $input.all();
return items.map(item => {
  const d       = item.json;
  const excerpt = d.chunk_text.slice(0, 400);
  const style   = PERSONA_VOICE_STYLE[d.persona_slug] ?? 'clear and informative';
  const script  = `Explain this study concept in 2-3 ${style} spoken sentences. No titles or bullets. Only the spoken words. Topic: ${excerpt}`;
  return { json: { ...d, tts_script: script } };
});

const responses = $input.all();
const scripts   = $('Build voiceover script').all();

const results = [];
for (let i = 0; i < responses.length; i++) {
  const response = responses[i].json;
  const prev     = scripts[i].json;

  const parts     = response?.candidates?.[0]?.content?.parts ?? [];
  const audioPart = parts.find(p => p.inlineData?.mimeType?.startsWith('audio/'));
  if (!audioPart) continue;

  const b64      = audioPart.inlineData.data;
  const mimeType = audioPart.inlineData.mimeType ?? 'audio/mpeg';
  const fileName = `${prev.persona_slug}-${prev.chunk_index}-voiceover.mp3`;
  const filePath = `${prev.material_id}/${fileName}`;

  results.push({
    json: {
      ...prev,
      audio_mime_type: mimeType,
      audio_file_path: filePath,
      audio_file_name: fileName,
    },
    binary: {
      audio_data: { data: b64, mimeType, fileName }
    }
  });
}
return results;

const uploads  = $input.all();
const audioExt = $('Extract audio data').all();
const supabaseUrl = $vars.SUPABASE_URL;

return uploads.map((_, i) => {
  const prev     = audioExt[i].json;
  const audioUrl = `${supabaseUrl}/storage/v1/object/public/post-media/${prev.audio_file_path}`;

  // Assemble the JSON payload stored in media_url
  const slideshowPayload = JSON.stringify({
    frames:           prev.frame_urls,
    audio_url:        audioUrl,
    frame_duration_ms: 2500,
  });

  return {
    json: {
      material_id: prev.material_id,
      persona_id:  prev.persona_id,
      post_type:   prev.post_type,
      title:       prev.title ?? null,
      body:        prev.chunk_text.slice(0, 300),
      media_type:  'slideshow',
      media_url:   slideshowPayload,
      source:      'n8n',
      sort_order:  prev.chunk_index * 4 + 3,
    }
  };
});
